import{_ as e,o as r,c as a,ag as o}from"./chunks/framework.OsDJF_Ea.js";const n="/docs/modules/granular-cloud.png",h=JSON.parse('{"title":"Granular Cloud","description":"","frontmatter":{},"headers":[],"relativePath":"modules/granular-cloud.md","filePath":"modules/granular-cloud.md"}'),s={name:"modules/granular-cloud.md"};function d(i,t,l,u,g,c){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="granular-cloud" tabindex="-1">Granular Cloud <a class="header-anchor" href="#granular-cloud" aria-label="Permalink to &quot;Granular Cloud&quot;">​</a></h1><p><strong>Category:</strong> Granular / Looping</p><p>4 independent granular layers sharing a single 500ms stereo capture buffer. Each layer can be frozen independently, creating up to 4 overlapping blurry textures. Layers are auto-panned across the stereo field. Much lower memory cost than multiple GranularDense instances.</p><img src="'+n+'" alt="granular-cloud module"><h2 id="inputs" tabindex="-1">Inputs <a class="header-anchor" href="#inputs" aria-label="Permalink to &quot;Inputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>inL</strong> (audio)</td><td>Left audio input.</td></tr><tr><td><strong>inR</strong> (audio)</td><td>Right audio input.</td></tr><tr><td><strong>grain_density</strong></td><td>Grains per second (all layers share same rate).</td></tr><tr><td><strong>grain_size_ms</strong></td><td>Grain window duration 10-100ms. Shorter grains = sharper frozen textures.</td></tr><tr><td><strong>dry_wet</strong></td><td>Dry/wet blend 0-1.</td></tr><tr><td><strong>stereo_width</strong></td><td>Stereo spread of grains across each layer&#39;s pan position.</td></tr><tr><td><strong>freeze_1</strong></td><td>Gate: rising edge toggles layer 1 freeze (PSRAM snapshot). Use Clock outputs for auto-cycling.</td></tr><tr><td><strong>freeze_2</strong></td><td>Gate: rising edge toggles layer 2 freeze.</td></tr><tr><td><strong>freeze_3</strong></td><td>Gate: rising edge toggles layer 3 freeze.</td></tr><tr><td><strong>freeze_4</strong></td><td>Gate: rising edge toggles layer 4 freeze.</td></tr><tr><td><strong>pitch</strong></td><td>Global pitch CV 0-1. Centre (0.5) = unison, 0.0 = 2 octaves down, 1.0 = 2 octaves up. Multiplies all layer pitch ratios.</td></tr><tr><td><strong>turbulence</strong></td><td>Texture depth 0-1. At 0 frozen layers are monolithic (EHX Freeze). At 1, per-grain size/pitch/direction are randomised for rich textural movement.</td></tr></tbody></table><h2 id="outputs" tabindex="-1">Outputs <a class="header-anchor" href="#outputs" aria-label="Permalink to &quot;Outputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>outL</strong> (audio)</td><td>Left granular audio.</td></tr><tr><td><strong>outR</strong> (audio)</td><td>Right granular audio.</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><p>Press freeze to latch a layer (PSRAM snapshot, content persists). Press again to unfreeze. Use Clock module with offset outputs into freeze_1..4 for automatic sequential cycling. Grain size controls the texture resolution of frozen layers. Turbulence adds per-grain randomisation of size, pitch, and direction during freeze -- 0 for monolithic, 1 for full textural movement. Connect an LFO to turbulence for evolving frozen textures. Mute individual layers with mute_1..4 PARAM.</p><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2>',11)])])}const f=e(s,[["render",d]]);export{h as __pageData,f as default};
